safe_example:
// SAFE: loaded from configuration / environment
public class DatabaseConfig
{
    private readonly string _connectionString;
    private readonly string _apiKey;

    public DatabaseConfig(IConfiguration config)
    {
        _connectionString = config.GetConnectionString("Main")
            ?? throw new InvalidOperationException("Main connection string not configured");
        _apiKey = config["ApiKey"]
            ?? Environment.GetEnvironmentVariable("API_KEY")
            ?? throw new InvalidOperationException("ApiKey not configured");
    }
}
